{"ideviceId":"idevice-1780335641819-c8xobqs4f","textInfoDurationInput":"","textInfoDurationTextInput":"Duración","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Agrupamiento","textTextarea":"<div style="font-family: Arial, sans-serif; max-width: 900px; margin: auto; background: #f6fff2; padding: 20px; border-radius: 20px; border: 3px solid #8bc34a;">
<h1 style="text-align: center;">🌱 Diario del crecimiento de nuestra planta 🌱</h1>
<p style="text-align: center; font-size: 18px;">Observamos nuestra planta y registramos sus cambios.</p>
<div style="background: white; padding: 20px; border-radius: 15px; margin-bottom: 20px;">
<h2>📝 Observación de hoy</h2>
<label><strong>📅 Fecha</strong></label><br /><input id="fecha" type="date" style="width: 100%; padding: 10px;" /><br /><br /><label><strong>📏 ¿Cuánto mide la planta?</strong></label><br /><input id="altura" type="text" placeholder="Ejemplo: 5 cm" style="width: 100%; padding: 10px;" /><br /><br /><label><strong>🍃 ¿Cuántas hojas tiene?</strong></label><br /><input id="hojas" type="number" style="width: 100%; padding: 10px;" /><br /><br /><label><strong>💧 ¿La hemos regado?</strong></label><br /><label><input type="radio" name="agua" value="Sí" /> Sí 🌧️</label> <label><input type="radio" name="agua" value="No" /> No ☀️</label> <br /><br /><label><strong>👀 ¿Qué cambios observas?</strong></label><br /><textarea id="observaciones" rows="5" placeholder="Ejemplo: Hoy ha salido una hoja nueva" style="width: 100%; padding: 10px;"></textarea> <br /><br /><label><strong>😊 ¿Cómo está la planta?</strong></label><br /><label><input type="radio" name="estado" value="Necesita ayuda" /> 😢 Necesita ayuda</label><br /><label><input type="radio" name="estado" value="Está bien" /> 🙂 Está bien</label><br /><label><input type="radio" name="estado" value="Crece mucho" /> 😍 Está creciendo mucho</label> <br /><br /><button onclick="guardarDatos()" style="background: #4caf50; color: white; border: none; padding: 15px 30px; border-radius: 10px; font-size: 18px; cursor: pointer;"> 💾 Guardar observación </button> <button onclick="borrarDatos()" style="background: #e53935; color: white; border: none; padding: 15px 30px; border-radius: 10px; font-size: 18px; cursor: pointer; margin-left: 10px;"> 🗑️ Reiniciar registro </button></div>
<div style="background: white; padding: 20px; border-radius: 15px;">
<h2>📚 Registro semanal</h2>
<table border="1" style="width: 100%; border-collapse: collapse; text-align: center;">
<tbody>
<tr style="background: #dcedc8;">
<th>Semana</th>
<th>Fecha</th>
<th>Altura</th>
<th>Hojas</th>
<th>Cambios observados</th>
</tr>
<tr>
<td>1</td>
<td contenteditable="true" id="s1f"></td>
<td contenteditable="true" id="s1a"></td>
<td contenteditable="true" id="s1h"></td>
<td contenteditable="true" id="s1c"></td>
</tr>
<tr>
<td>2</td>
<td contenteditable="true" id="s2f"></td>
<td contenteditable="true" id="s2a"></td>
<td contenteditable="true" id="s2h"></td>
<td contenteditable="true" id="s2c"></td>
</tr>
<tr>
<td>3</td>
<td contenteditable="true" id="s3f"></td>
<td contenteditable="true" id="s3a"></td>
<td contenteditable="true" id="s3h"></td>
<td contenteditable="true" id="s3c"></td>
</tr>
<tr>
<td>4</td>
<td contenteditable="true" id="s4f"></td>
<td contenteditable="true" id="s4a"></td>
