<td contenteditable="true" id="s4c"></td>
</tr>
</tbody>
</table>
<p>✏️ Puedes escribir directamente en la tabla.</p>
</div>
</div>
<p>
<script>
function guardarDatos() {

let datos = {
fecha: document.getElementById("fecha").value,
altura: document.getElementById("altura").value,
hojas: document.getElementById("hojas").value,
observaciones: document.getElementById("observaciones").value,
agua: document.querySelector('input[name="agua"]:checked')?.value || "",
estado: document.querySelector('input[name="estado"]:checked')?.value || "",

tabla: {
s1f: document.getElementById("s1f").innerText,
s1a: document.getElementById("s1a").innerText,
s1h: document.getElementById("s1h").innerText,
s1c: document.getElementById("s1c").innerText,

s2f: document.getElementById("s2f").innerText,
s2a: document.getElementById("s2a").innerText,
s2h: document.getElementById("s2h").innerText,
s2c: document.getElementById("s2c").innerText,

s3f: document.getElementById("s3f").innerText,
s3a: document.getElementById("s3a").innerText,
s3h: document.getElementById("s3h").innerText,
s3c: document.getElementById("s3c").innerText,

s4f: document.getElementById("s4f").innerText,
s4a: document.getElementById("s4a").innerText,
s4h: document.getElementById("s4h").innerText,
s4c: document.getElementById("s4c").innerText
}
};

localStorage.setItem("registroPlanta", JSON.stringify(datos));
alert("✅ Observación guardada");
}

function cargarDatos() {

let datos = JSON.parse(localStorage.getItem("registroPlanta"));

if (!datos) return;

document.getElementById("fecha").value = datos.fecha || "";
document.getElementById("altura").value = datos.altura || "";
document.getElementById("hojas").value = datos.hojas || "";
document.getElementById("observaciones").value = datos.observaciones || "";

if (datos.agua) {
document.querySelector(`input[name="agua"][value="${datos.agua}"]`).checked = true;
}

if (datos.estado) {
document.querySelector(`input[name="estado"][value="${datos.estado}"]`).checked = true;
}

for (let id in datos.tabla) {
document.getElementById(id).innerText = datos.tabla[id];
}
}

function borrarDatos() {
localStorage.removeItem("registroPlanta");
location.reload();
}

window.onload = cargarDatos;
</script>
</p>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}
